<?phpnamespace app\dep\Chat;use app\model\Chat\ChatModel;use app\enum\CommonEnum;class ChatDep{    public $model;    public function __construct()    {        $this->model = new ChatModel();    }    public function first($id)    {        $res = $this->model->where('id', $id)->first();        return $res;    }    public function firstBySuperAdmin()    {        $res = $this->model->where('name', '超级管理员')->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstByAdmin()    {        $res = $this->model->where('name', '管理员')->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstByTitle($name)    {        $res = $this->model->where('title', $name)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function getUserByToken($token)    {        $res = $this->model->where('token', $token)->first();        return $res;    }    public function firstByEmail($email)    {        $res = $this->model->where('email', $email)->first();        return $res;    }    public function firstByToken($token)    {        $res = $this->model->where('token', $token)->first();        return $res;    }    public function all()    {        $res = $this->model->all();        return $res;    }    public function allOK()    {        $res = $this->model->where('is_del', CommonEnum::NO)->get();        return $res;    }    public function add($data)    {        $res = $this->model->insertGetId($data);        return $res;    }    public function edit($id, $data)    {        if (!is_array($id)) {            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function batchEdit($ids, $data)    {        $res = $this->model->whereIn('id', $ids)->update($data);        return $res;    }    public function del($id)    {        if (!is_array($id)) {            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->delete();        return $res;    }    public function list($param)    {        $res = $this->model//            ->where('is_del', CommonEnum::NO)            ->when(!empty($param['user_id']), function ($query) use ($param) {                $query->where('user_id', $param['user_id']);            })            ->when(!empty($param['content']), function ($query) use ($param) {                $query->where('content','like' ,"%{$param['content']}%");            })            ->orderBy('id', 'desc')            ->paginate($param['page_size'], ['*'], 'page', $param['current_page']);        return $res;    }}